import{_ as e,p as c,q as d,a1 as o}from"./framework-5866ffd3.js";const a={},t=o('<h1 id="uri拼接规则" tabindex="-1"><a class="header-anchor" href="#uri拼接规则" aria-hidden="true">#</a> Uri拼接规则</h1><p>所有的Uri拼接都是通过Uri(Uri baseUri, Uri relativeUri)这个构造器生成。</p><h2 id="带-结尾的baseuri" tabindex="-1"><a class="header-anchor" href="#带-结尾的baseuri" aria-hidden="true">#</a> 带<code>/</code>结尾的baseUri</h2><ul><li><code>http://a.com/</code> + <code>b/c/d</code> = <code>http://a.com/b/c/d</code></li><li><code>http://a.com/path1/</code> + <code>b/c/d</code> = <code>http://a.com/path1/b/c/d</code></li><li><code>http://a.com/path1/path2/</code> + <code>b/c/d</code> = <code>http://a.com/path1/path2/b/c/d</code></li></ul><h2 id="不带-结尾的baseuri" tabindex="-1"><a class="header-anchor" href="#不带-结尾的baseuri" aria-hidden="true">#</a> 不带<code>/</code>结尾的baseUri</h2><ul><li><code>http://a.com</code> + <code>b/c/d</code> = <code>http://a.com/b/c/d</code></li><li><code>http://a.com/path1</code> + <code>b/c/d</code> = <code>http://a.com/b/c/d</code></li><li><code>http://a.com/path1/path2</code> + <code>b/c/d</code> = <code>http://a.com/path1/b/c/d</code></li></ul><p>事实上<code>http://a.com</code>与<code>http://a.com/</code>是完全一样的，他们的path都是<code>/</code>，所以才会表现一样。为了避免低级错误的出现，请使用的标准baseUri书写方式，即使用<code>/</code>作为baseUri的结尾的第一种方式。</p>',7),i=[t];function h(r,p){return c(),d("div",null,i)}const s=e(a,[["render",h],["__file","url-rule.html.vue"]]);export{s as default};
